package settings

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/settings"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type InstanceSettingsProxy struct {
	settings.UnimplementedInstanceSettingsServer
	client settings.InstanceSettingsClient
}

func init() {
	proxyutil.Register(&settings.InstanceSettings_ServiceDesc, NewInstanceSettingsProxy)
}
func NewInstanceSettingsProxy(cc grpc.ClientConnInterface) settings.InstanceSettingsServer {
	return &InstanceSettingsProxy{client: settings.NewInstanceSettingsClient(cc)}
}
func (p *InstanceSettingsProxy) GetSettingsFields(ctx context.Context, in *settings.GetFieldsRequest) (*settings.GetFieldsResponse, error) {
	return proxyutil.ProxyMethod[settings.GetFieldsRequest, settings.GetFieldsResponse](p.client.GetSettingsFields)(ctx, in)
}
func (p *InstanceSettingsProxy) ValidateForm(ctx context.Context, in *settings.ValidateFormRequest) (*settings.ValidateFormResponse, error) {
	return proxyutil.ProxyMethod[settings.ValidateFormRequest, settings.ValidateFormResponse](p.client.ValidateForm)(ctx, in)
}
